SELECT SUM(total_flakes) AS total_flakes_dev
FROM test_flakes
WHERE test_environment = 'development';

SELECT test_id, SUM(flake_count) AS total_flakes
FROM flake_tests
GROUP BY test_id;

SELECT total_flakes
FROM test_flakes
WHERE test_id = 1;

SELECT commit_hash
FROM commit_details
WHERE commit_message LIKE '%Add new feature%';

SELECT test_environment
FROM flake_tests
WHERE flake_count > 0;

SELECT test_id, total_flakes
FROM test_flakes
ORDER BY total_flakes DESC;

SELECT test_id, MAX(total_flakes) as max_total_flakes
     FROM test_flakes
     GROUP BY test_id;
